parameters.jsCode:
// Generate PO record and prepare Airtable payload
const data = $input.first().json.body || $input.first().json;

const poNum = 'PO-' + new Date().getFullYear() + '-' + String(Date.now()).slice(-4);
const totalAmount = data.total_amount || (data.quantity_requested * (data.unit_cost || 0));

const poRecord = {
  po_number: poNum,
  vendor_name: data.vendor_name || 'TBD',
  vendor_email: data.vendor_email || '',
  department: data.department || '',
  total_amount: totalAmount,
  items_json: data.items_json || JSON.stringify([{ item_name: data.item_name, quantity: data.quantity_requested || data.approved_quantity, unit: data.unit || 'each', unit_price: data.unit_cost || 0 }]),
  gl_account: data.gl_code || data.gl_account || '',
  source: data.source || 'Manual',
  requester: data.requester || 'System',
  status: 'Pending Approval'
};

const createBody = JSON.stringify({ records: [{ fields: poRecord }] });

return [{ json: { ...poRecord, total_amount: totalAmount, create_body: createBody } }];

// Extract PO data from Airtable response and merge with original context
const airtableResp = $input.first().json;
const record = airtableResp.records?.[0] || airtableResp;
const original = $('Code - Prepare PO Record').first().json;

return [{ json: {
  po_number: original.po_number,
  vendor_name: original.vendor_name,
  vendor_email: original.vendor_email,
  department: original.department,
  total_amount: original.total_amount,
  items_json: original.items_json,
  gl_account: original.gl_account,
  source: original.source,
  requester: original.requester,
  airtable_record_id: record.id || record.records?.[0]?.id || ''
} }];

